@ax7.proof(
    dummy_variables=(
        "t:setvar",
    ),
    distinct=(
        ("t", "x"),
        ("t", "y"),
        ("t", "z"),
    ),
)
def prove_ax7(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s000 import a1i
    from metamath_setmm_provider.shards.s002 import ex, imp
    from metamath_setmm_provider.shards.s003 import syl2and
    from metamath_setmm_provider.shards.s009 import exlimiiv


    _step_1 = proof.use(
        ax7v2,
        subst={
            "x": "x",
            "y": "t",
            "z": "y",
        },
    )  # ⊢ wi(wceq(cv(x), cv(t)), wi(wceq(cv(x), cv(y)), wceq(cv(t), cv(y))))
    _step_2 = proof.use(
        ax7v2,
        subst={
            "x": "x",
            "y": "t",
            "z": "z",
        },
    )  # ⊢ wi(wceq(cv(x), cv(t)), wi(wceq(cv(x), cv(z)), wceq(cv(t), cv(z))))
    _step_3 = proof.use(
        ax7v1,
        subst={
            "x": "t",
            "y": "y",
            "z": "z",
        },
    )  # ⊢ wi(wceq(cv(t), cv(y)), wi(wceq(cv(t), cv(z)), wceq(cv(y), cv(z))))
    _step_4 = proof.use(
        imp,
        _step_3,
    )  # ⊢ wi(wa(wceq(cv(t), cv(y)), wceq(cv(t), cv(z))), wceq(cv(y), cv(z)))
    _step_5 = proof.use(
        a1i,
        _step_4,
        subst={
            "ps": "wceq(cv(x), cv(t))",
        },
    )  # ⊢ wi(wceq(cv(x), cv(t)), wi(wa(wceq(cv(t), cv(y)), wceq(cv(t), cv(z))), wceq(cv(y), cv(z))…
    _step_6 = proof.use(
        syl2and,
        _step_1,
        _step_2,
        _step_5,
    )  # ⊢ wi(wceq(cv(x), cv(t)), wi(wa(wceq(cv(x), cv(y)), wceq(cv(x), cv(z))), wceq(cv(y), cv(z))…
    _step_7 = proof.use(ax6evr, subst={"x": "t", "y": "x"})  # ⊢ wex(wceq(cv(x), cv(t)), t)
    _step_8 = proof.use(
        exlimiiv,
        _step_6,
        _step_7,
    )  # ⊢ wi(wa(wceq(cv(x), cv(y)), wceq(cv(x), cv(z))), wceq(cv(y), cv(z)))
    _step_9 = proof.use(
        ex,
        _step_8,
    )  # ⊢ wi(wceq(cv(x), cv(y)), wi(wceq(cv(x), cv(z)), wceq(cv(y), cv(z))))
    return proof.qed(_step_9)


